"""
MKT Christ Commentary — Judges chapters 11–13
Run: python3 scripts/zc-christ-judges-11-13.py

Source data used:
- data/interlinear/judges.json
- data/commentary/mkt-christ/judges.json (chs 1–6 already present)

Key typological decisions:
- Jephthah (11:1-3): rejected son who becomes deliverer — the most direct outcast-redeemer type before Joseph
- Jephthah's diplomacy (11:12-28): the covenant argument made to an alien king — Christ argues the Father's case before the whole cosmos
- Spirit on Jephthah (11:29): Spirit-anointing of deliverer points to Christ's baptism
- Jephthah's vow (11:30-31): costly unreserved vow; the daughter's voluntary acceptance shadows Christ's submission to the Father's will
- Mourning custom (11:39-40): annual lament for Jephthah's daughter shadows Zech 12:10-11 mourning for the pierced one
- Shibboleth test (12:6): the word that reveals true identity — a type of confessing Christ as Lord
- Barren wife announcement (13:3): miraculous birth pattern culminates in the virgin birth
- "Pelî'" name (13:18): the 'Wonderful' name anticipates Isa 9:6
- Angel ascending in flame (13:20): divine self-disclosure pointing to the ascension
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JUDGES = {
  "11": {
    "1": "<p>A type: Jephthah is introduced as a <em>gibbôr ḥayil</em> — a mighty warrior — born of a prostitute and driven out by his half-brothers. He is the most explicit outcast-redeemer type before Joseph in the Judges cycle. As Joseph was sold by his brothers and exiled to Egypt only to become their savior, Jephthah is expelled by those who should have protected him and later becomes the very one Gilead needs for survival. The pattern points to Christ, who &ldquo;came to his own, and his own people did not receive him&rdquo; (John 1:11) and who, born under scandalous circumstances in a backwater town, was despised and rejected (Isa 53:3) before rising as the deliverer of all.</p>",
    "2": "<p>A shadow: the legitimate sons drive Jephthah out with the words &ldquo;you shall not have an inheritance in our father&rsquo;s house, for you are the son of another woman.&rdquo; The exclusion from the father&rsquo;s house on the basis of birth mirrors the exclusion Christ endured — questioned at birth (Matt 1:18-19), doubted by his brothers (John 7:5), and ultimately cast outside the city gate (Heb 13:12). Yet the one excluded from human inheritance becomes the heir of all things (Heb 1:2).</p>",
    "3": "<p>A theme: Jephthah flees to the land of Tob and &ldquo;worthless men gathered around him and went out with him.&rdquo; The rejected deliverer surrounded by social outcasts mirrors the company Christ kept — tax collectors, sinners, fishermen, those the religious establishment dismissed. His disciples were not the respectable; he gathered those the world considered worthless and made them the foundation of the church (1 Cor 1:26-28).</p>",
    "4": "<p>A theme: the Ammonite threat against Israel triggers the crisis that makes the elders of Gilead think of Jephthah. The external pressure that drives Israel to seek the rejected deliverer mirrors the pattern in which affliction drives people to Christ. The need that human resources cannot meet becomes the opening through which the previously despised one is recognized as indispensable.</p>",
    "5": "<p>A theme: the elders of Gilead go to Jephthah to bring him back. The community that expelled its deliverer must seek him in humility. This reversal — the rejectors becoming petitioners — anticipates the day when every knee bows and every tongue confesses that the one they rejected is Lord (Phil 2:10-11). No one can receive what Jephthah alone can give without coming to him.</p>",
    "6": "<p>A type: &ldquo;Come and be our leader, that we may fight against the Ammonites.&rdquo; The elders appoint Jephthah both military commander (<em>qāṣîn</em>) and head (<em>rōʾš</em>) — the rejected son is called to be both warrior and ruler. Christ&rsquo;s double role as the one who defeats the enemy (the warrior aspect) and reigns over the redeemed (the king aspect) is foreshadowed here.</p>",
    "7": "<p>A revelation of God: Jephthah confronts the elders with the truth of their past behavior: &ldquo;Did you not hate me and drive me out of my father&rsquo;s house?&rdquo; The deliverer does not pretend the rejection did not happen; he names it plainly. Christ similarly does not conceal the history of Israel&rsquo;s rejection of the prophets and of himself (Matt 23:37; Luke 13:34), but he accepts the commission anyway. Honest confrontation of the past does not prevent the work of redemption.</p>",
    "8": "<p>A theme: the elders acknowledge their change of heart — now they turn to Jephthah in their distress. The condition Jephthah sets is that the same LORD who gives the victory will make him head over Gilead. Jephthah ties his authority entirely to divine confirmation rather than human appointment. Christ likewise claims his authority from the Father alone (John 5:27; Matt 28:18), not from human endorsement.</p>",
    "9": "<p>A theme: Jephthah frames the commission conditionally on YHWH&rsquo;s action: &ldquo;if the LORD gives them over to me.&rdquo; The deliverer acts as an instrument of divine power, not an autonomous warrior. All genuine deliverance is in this form: the human agent accomplishes only what YHWH enables. Christ&rsquo;s works were done in this same dependence — &ldquo;the Son can do nothing of his own accord, but only what he sees the Father doing&rdquo; (John 5:19).</p>",
    "10": "<p>A theme: &ldquo;The LORD will be witness between us, if we do not do as you say.&rdquo; The covenant between Jephthah and Gilead is sealed with YHWH as the guarantor. Every human covenant that appeals to YHWH as witness points to the ultimate covenant — the new covenant ratified by Christ&rsquo;s blood (Luke 22:20) — in which God himself is both party and guarantor.</p>",
    "11": "<p>A type: Jephthah speaks all his words before YHWH at Mizpah, before the community and before God simultaneously. The enthronement of the rejected son before YHWH parallels the heavenly session of Christ: the one who was humiliated, rejected, and cast out is seated at the right hand of the Father (Ps 110:1; Heb 1:3), publicly vindicated before the cosmos.</p>",
    "12": "<p>A theme: Jephthah sends messengers to the king of Ammon asking &ldquo;What do you have against me, that you have come to me to fight against my land?&rdquo; The deliverer first attempts to resolve the conflict through word — through diplomatic argument — before resorting to battle. Christ likewise first came with the word of the gospel, offering reconciliation before the final judgment (2 Cor 5:19-20: &ldquo;God was reconciling the world to himself in Christ&rdquo;).</p>",
    "13": "<p>A theme: the king of Ammon claims Israel wrongfully took his land when they came from Egypt. Jephthah&rsquo;s response will be a detailed historical argument. The confrontation between the covenant people and a hostile power claiming prior rights over covenant land prefigures the ultimate confrontation: the one who claims rights over humanity by virtue of sin and death (the &ldquo;ruler of this world&rdquo;) is answered not by force first but by the truth of redemptive history.</p>",
    "14": "<p>A theme: Jephthah sends back a counter-argument. The deliverer stands as an advocate who makes the covenant case. This role of Jephthah as the one who speaks on behalf of Israel before a hostile court prefigures Christ as the advocate (<em>paraklētos</em>) who intercedes for his people (1 John 2:1; Rom 8:34).</p>",
    "15": "<p>A theme: Jephthah&rsquo;s argument begins with a historical denial — Israel did not take Moab&rsquo;s or Ammon&rsquo;s land. The appeal to the exact sequence of events from the Exodus to the conquest demonstrates that covenant history is the framework for all territorial claims. Christ similarly grounds his claims in the full arc of redemptive history (Luke 24:44-47: &ldquo;everything written about me in the Law of Moses and the Prophets and the Psalms must be fulfilled&rdquo;).</p>",
    "16": "<p>A theme: the careful recitation of the wilderness route — through the wilderness from the Red Sea to Kadesh — shows YHWH guided Israel around rather than through hostile territory. The same divine detour logic governs the redemptive journey: Israel&rsquo;s forty years in the wilderness are the necessary formation-before-inheritance, just as the long OT era of preparation preceded Christ&rsquo;s coming in the fullness of time (Gal 4:4).</p>",
    "17": "<p>A theme: Israel requested peaceful passage through Edom and Moab and was refused. Israel went around rather than forcing the issue. The pattern of seeking peaceful coexistence before resorting to warfare mirrors the divine patience before judgment. God&rsquo;s wrath is never hasty; his offer of reconciliation (2 Pet 3:9: &ldquo;not wishing that any should perish&rdquo;) precedes judgment.</p>",
    "18": "<p>A theme: Israel camped in the wilderness of Moab beyond the Arnon, not entering Moab&rsquo;s territory. The precise respecting of boundaries — even the border of an unfriendly nation — demonstrates covenant integrity. Christ fulfilled all righteousness (Matt 3:15) by honoring every boundary the Father established, never overreaching, perfectly obedient to the scope of his commission.</p>",
    "19": "<p>A theme: Israel sent messengers to Sihon king of Heshbon requesting passage, and Sihon refused. The hostile refusal of Sihon led to battle — YHWH gave him into Israel&rsquo;s hand. The principle that those who refuse the peaceful overture of God&rsquo;s people will eventually face divine judgment is the consistent pattern: the same gospel that offers life becomes the testimony against those who reject it (John 12:48).</p>",
    "20": "<p>A theme: &ldquo;YHWH God of Israel gave Sihon and all his people into the hand of Israel.&rdquo; The victories over Sihon and Og were paradigmatic for Israel&rsquo;s self-understanding — proof texts of YHWH&rsquo;s power cited repeatedly (Pss 135:11; 136:19-20). Each instance of YHWH giving enemies into his people&rsquo;s hand is a partial fulfillment of the promise that all enemies will ultimately be put under the feet of the Son (1 Cor 15:25-27).</p>",
    "21": "<p>A theme: all the Amorites are dispossessed and Israel inherits their land. The transfer of inheritance from the disinherited Amorites to the covenant people is the economic logic of atonement writ large: what the guilty possessed is given to those declared righteous. The NT applies this logic to sin: through Christ&rsquo;s atoning work, the inheritance that sin disqualified humanity from possessing is restored (1 Pet 1:4).</p>",
    "22": "<p>A theme: Israel possessed all the territory from the Arnon to the Jabbok. The specific boundary markers — from river to river — define the scope of the inheritance exactly as covenant-granted. The precision of the promised land&rsquo;s borders mirrors the precision of the redemption Christ accomplished: he did not win a vague or approximate salvation but secured an exact inheritance for an exact people (John 10:28-29; Rev 21:27).</p>",
    "23": "<p>A revelation of God: &ldquo;So then YHWH the God of Israel dispossessed the Amorites from before his people Israel; and should you possess them?&rdquo; Jephthah&rsquo;s argument peaks with the theological claim: it is YHWH who fights; whatever he gives, he gives by right of divine sovereignty. The refusal to acknowledge YHWH&rsquo;s sovereign grants is the root of all human conflict with God&rsquo;s covenant purposes. Those who fight against what God has given Christ to possess — his people, his church — are fighting against divine sovereignty itself.</p>",
    "24": "<p>A theme: Jephthah uses the logic of each people&rsquo;s god giving them their land — even arguing from within the frame of Chemosh, Ammon&rsquo;s god. The diplomatic tactic of acknowledging the worldview of the opponent before making the decisive theological claim anticipates Paul&rsquo;s use of Areopagus and Athenian poetry (Acts 17:28) as entry points for the gospel. The truth is made accessible through meeting people where they are.</p>",
    "25": "<p>A theme: &ldquo;Are you any better than Balak son of Zippor, king of Moab? Did he ever contend against Israel?&rdquo; The appeal to historical precedent — even Balak knew better than to fight what YHWH had granted — is an argument from negative example. The NT similarly argues from negative examples: &ldquo;these things happened to them as examples and were written down as warnings for us&rdquo; (1 Cor 10:11).</p>",
    "26": "<p>A theme: three hundred years of occupation — Israel in Heshbon and its villages for three centuries without Ammonite challenge. The long-standing possession validates the covenant claim. Christ&rsquo;s claims are similarly grounded in the long arc of covenant history: the promises to Abraham, David, and the prophets, accumulated over millennia, all point to him. No latecoming rival claim can overturn a redemptive history that God himself authorized.</p>",
    "27": "<p>A revelation of God: &ldquo;I have not sinned against you, but you have done me wrong by fighting against me. The LORD, the Judge, decide this day between the people of Israel and the people of Ammon.&rdquo; Jephthah appeals to YHWH as the ultimate judge. Every claim of human justice reaches its limit and must finally be submitted to divine adjudication. The NT presents Christ himself as the appointed judge before whom all disputes are finally settled (Acts 17:31; 2 Cor 5:10).</p>",
    "28": "<p>A theme: &ldquo;But the king of the Ammonites did not listen to the words of Jephthah that he sent to him.&rdquo; The rejection of the messenger and his message leads to judgment. The same pattern governs the gospels: those who refuse Christ&rsquo;s peace-offer face the consequences of their refusal (Luke 19:41-44; Matt 22:7). The gospel offer is genuine and extended in good faith; rejection is willful, not forced.</p>",
    "29": "<p>A type: &ldquo;Then the Spirit of the LORD was upon Jephthah.&rdquo; The Spirit comes on Jephthah at the decisive moment of his public service as deliverer. The pattern of Spirit-anointing accompanying the commencement of redemptive mission is fulfilled at Jesus&rsquo; baptism when &ldquo;the Spirit of God descended like a dove and came to rest on him&rdquo; (Matt 3:16), inaugurating his public ministry. Every Spirit-anointed deliverer in the OT is a partial anticipation of the one who will be anointed &ldquo;without measure&rdquo; (John 3:34).</p>",
    "30": "<p>A shadow: Jephthah vows a vow to YHWH: &ldquo;If you will give the Ammonites into my hand, then whatever comes out from the doors of my house to meet me when I return in peace from the Ammonites shall be the LORD&rsquo;s, and I will offer it up for a burnt offering.&rdquo; The vow places the entire outcome in YHWH&rsquo;s hands and pledges an unreserved sacrifice. The recklessness of the vow points to the difference between human and divine sacrificial logic: Christ&rsquo;s self-offering was not rash but deliberate, foreknown from before the foundation of the world (1 Pet 1:19-20), and he is the lamb that the Father himself provides (Gen 22:8).</p>",
    "31": "<p>A shadow: the form of the vow — &ldquo;whatever comes out from the doors of my house&rdquo; — was intended for a household servant or animal, but fate and circumstance turn it toward his only child. The unintended direction of the sacrifice shadows the way the cross worked: what was meant to be a political execution became the divinely ordained sacrifice for the world&rsquo;s sin. In both cases, the human intention does not fully comprehend the divine purpose hidden within the event.</p>",
    "32": "<p>A theme: &ldquo;So Jephthah crossed over to the Ammonites to fight against them, and the LORD gave them into his hand.&rdquo; The battle follows immediately on the Spirit-anointing and the vow. YHWH delivers the enemy because the deliverer has completely committed himself — nothing held back, the outcome surrendered to God. Christ&rsquo;s total self-giving (&ldquo;not my will, but yours be done&rdquo; — Luke 22:42) is the perfect form of what Jephthah&rsquo;s vow pointed toward.</p>",
    "33": "<p>A theme: twenty cities struck from Aroer to the entrance of Minnith — a complete victory sweep. The breadth and completeness of the conquest echoes the scope of Christ&rsquo;s victory: not a partial or regional triumph but a total defeat of the enemy on every front (Col 2:15: &ldquo;disarmed the rulers and authorities and put them to open shame, triumphing over them&rdquo;).</p>",
    "34": "<p>A shadow: Jephthah&rsquo;s daughter comes out first to meet him &ldquo;with tambourines and dancing.&rdquo; She is his <em>yĕḥîdāh</em> — his only one — and he had no other children. The only child who becomes the sacrifice&rsquo;s subject is a profound echo of Gen 22 (Abraham&rsquo;s only son Isaac). Both point forward to the Father&rsquo;s sacrifice of his <em>monogenēs</em> (only-begotten) Son (John 3:16). The beloved only child and the willingness of the parent to honor the vow at ultimate cost: both shadows have one fulfillment.</p>",
    "35": "<p>A shadow: Jephthah tears his clothes and cries &ldquo;Alas, my daughter! You have brought me very low&rdquo; — but he confesses he has made his vow and cannot take it back. The anguish of the father who cannot undo the vow he made to God points to Gethsemane: the Father&rsquo;s love for the Son is real, the cost is real, but the covenant purpose is not reversed (Matt 26:39; Isa 53:10: &ldquo;it was the will of the LORD to crush him&rdquo;). The grief does not cancel the obedience.</p>",
    "36": "<p>A type: the daughter&rsquo;s response is one of the most striking in the OT: &ldquo;My father, you have opened your mouth to the LORD; do to me according to what has gone out of your mouth.&rdquo; She accepts her fate as bound by the covenant her father made with God. This voluntary acceptance of the covenant&rsquo;s costly consequences mirrors Christ&rsquo;s own submission: &ldquo;not my will, but yours, be done&rdquo; (Luke 22:42). Both the daughter and the Son align their own will with the Father&rsquo;s unreserved vow.</p>",
    "37": "<p>A shadow: she asks for two months to &ldquo;go up and down on the mountains and weep for my virginity.&rdquo; She will die without bearing children — without legacy, without continuation of her name. Christ also died without physical descendants, without a biological legacy in the ordinary sense. Yet both deaths produced something extraordinary: a legacy beyond biological line. The daughter&rsquo;s annual memorial, and Christ&rsquo;s resurrection community, continue what death seemed to end.</p>",
    "38": "<p>A theme: her father grants her request and she goes for two months with her companions. The space of mourning before the appointed time of sacrifice is granted. In the same way, Jesus&rsquo; forty days of wilderness testing and his three years of ministry precede the cross — not delaying it, but filling the appointed space before it.</p>",
    "39": "<p>A shadow: at the end of the two months she returns, and Jephthah does with her according to his vow, &ldquo;and she had never known a man.&rdquo; The death of a consecrated virgin carries deep typological weight: her complete devotion to YHWH, her dying in service of her father&rsquo;s covenant, her virginity left intact — all point to a sacrificial consecration that transcends ordinary human categories. Christ&rsquo;s death was also the death of the consecrated, the sinless one, who offered himself without blemish (Heb 9:14).</p>",
    "40": "<p>A shadow: the daughters of Israel establish an annual four-day custom to &ldquo;lament the daughter of Jephthah the Gileadite.&rdquo; This institutionalized mourning over a sacrificial figure who gave herself for the covenant mirrors the deeper mourning prophesied in Zechariah: &ldquo;they will mourn for him, as one mourns for an only child, and weep bitterly over him, as one weeps over a firstborn&rdquo; (Zech 12:10). The annual grief that ritualizes an unrepeatable sacrifice points to the Lord&rsquo;s Supper — the repeated memorial of Christ&rsquo;s once-for-all offering that keeps his death before the community until he comes (1 Cor 11:26).</p>"
  },
  "12": {
    "1": "<p>A theme: the men of Ephraim muster and threaten Jephthah — &ldquo;Why did you cross over to fight against the Ammonites and did not call us to go with you?&rdquo; Tribal jealousy over the honor of the victory mirrors the human tendency to resent what God does through others rather than rejoicing in the common deliverance. The NT corrects this posture: &ldquo;Rejoice with those who rejoice&rdquo; (Rom 12:15); the unity of the Spirit requires laying down the competition for honor (Phil 2:3-4).</p>",
    "2": "<p>A theme: Jephthah replies that he did call them and they did not come. The argument over who deserves credit for the victory echoes the recurring human problem of dishonoring the deliverer. Christ himself was questioned about his authority and the source of his power (Matt 21:23; Mark 11:28); the deliverance accomplished does not automatically produce gratitude or acknowledgment.</p>",
    "3": "<p>A theme: &ldquo;I took my life in my hand and crossed over against the Ammonites, and the LORD gave them into my hand.&rdquo; Jephthah stakes his own life on the mission — exactly what a deliverer does. Christ likewise did not preserve himself but gave his life: &ldquo;No one takes it from me, but I lay it down of my own accord&rdquo; (John 10:18). The willingness to put one&rsquo;s life at risk for the community&rsquo;s salvation is the defining mark of the true shepherd-deliverer.</p>",
    "4": "<p>A theme: the intra-Israelite conflict — Gilead fights Ephraim — reveals the tragic fragmentation that sin and pride produce within the covenant community. What should be a unified response to deliverance becomes civil war. The NT addresses this same fracturing tendency: &ldquo;there is neither Jew nor Greek, there is neither slave nor free, there is no male and female, for you are all one in Christ Jesus&rdquo; (Gal 3:28); tribal pride is dissolved in the one body (Eph 4:4-6).</p>",
    "5": "<p>A theme: the Gileadites seize the fords of the Jordan against Ephraim. Control of the crossing-points — the liminal spaces between regions — is the military key. The Jordan crossing carries deep typological weight throughout the OT: Israel crosses into the promised land under Joshua; Elijah and Elisha cross before the prophetic succession; John baptizes in the Jordan where Jesus&rsquo; public ministry begins. Every significant Jordan crossing points to the ultimate entry into the inheritance.</p>",
    "6": "<p>A type: the shibboleth test — &ldquo;say <em>shibbōlet</em>&rdquo; — reveals identity by the ability or inability to produce the correct sound. Those who could not say it correctly were slain at the crossing. The word that divides the genuine from the counterfeit is a type of confessing Christ: &ldquo;no one can say &lsquo;Jesus is Lord&rsquo; except in the Holy Spirit&rdquo; (1 Cor 12:3). Authentic confession — not mere intellectual assent but Spirit-enabled declaration — is the shibboleth of the new covenant community. The test at the Jordan crossing points forward to the baptismal confession made at the water.</p>",
    "7": "<p>A theme: Jephthah judges Israel six years and then dies, buried in his city. The judge who delivered Israel serves for a limited term and then passes off the scene. The finitude of every human deliverer — each one dies, each one&rsquo;s term ends — is the structural argument for Christ&rsquo;s permanent, indestructible priesthood and kingship (Heb 7:23-24: &ldquo;the former priests were many in number, because they were prevented by death from continuing in office, but he holds his priesthood permanently&rdquo;).</p>",
    "8": "<p>A theme: Ibzan of Bethlehem judged Israel. The mention of Bethlehem — the future birthplace of David and of Christ — in the list of judges&rsquo; cities is a quiet geographic marker in the typological pattern. The most significant figure to come from Bethlehem is not named here; these minor judges hold the place temporally until the arrival of the Davidic kingship and its messianic fulfillment (Mic 5:2).</p>",
    "9": "<p>A theme: Ibzan had thirty sons and thirty daughters — a prosperous family of the covenant community. The large families of the minor judges signal blessing and continuation of God&rsquo;s covenant people through each generation. The covenant&rsquo;s faithfulness across generations despite Israel&rsquo;s apostasy points to the preserving grace of God that culminates in the messianic line remaining intact through all of Israel&rsquo;s failures.</p>",
    "10": "<p>A theme: Ibzan judged Israel seven years and died. Another short tenure, another ending. The catalog of judges who served and died is the formal structure of Hebrews&rsquo; argument: the Levitical system, the human succession, the repeated passing-of-the-baton all demonstrate that the old order was not the final solution. The endless list of successors points to the one who needs no successor.</p>",
    "11": "<p>A theme: Elon the Zebulunite judged Israel ten years. The tribal diversity of the judges — Judah, Benjamin, Manasseh, Gilead, Ephraim, Zebulun — reflects the covenant&rsquo;s reach across all twelve tribes. No tribe is too obscure or too remote to receive the gift of a deliverer. Christ likewise came not to one region but to &ldquo;all nations&rdquo; (Matt 28:19), and his Spirit was poured out on &ldquo;all flesh&rdquo; (Acts 2:17).</p>",
    "12": "<p>A theme: Elon died and was buried in Aijalon — the same valley where the sun stood still for Joshua (Josh 10:12). The minor judge buried in the valley of Joshua&rsquo;s great miracle is an apt image: the place of extraordinary past grace becomes a burial ground for those who follow. Every location of divine action becomes part of the geography of redemption, all pointing toward the resurrection of the one who transforms burial sites permanently (John 11:25).</p>",
    "13": "<p>A theme: Abdon the son of Hillel the Pirathonite judged Israel eight years. Pirathon was in Ephraim&rsquo;s hill country. The judge from the very tribe that had just attacked Jephthah (v1) now serves Israel — the fractured community is sustained by the Lord through successors from every quarter. Divine providence works through every tribe, even those who have proven faithless.</p>",
    "14": "<p>A theme: Abdon had forty sons and thirty grandsons who rode on seventy donkeys — a detail signaling status, wealth, and influence. The seventy riders on donkeys prefigure the messianic entry on a donkey (Zech 9:9; Matt 21:5) in inverted form: where Abdon&rsquo;s family displayed status through many donkeys, the true king displays his kingdom by entering on one, in humility.</p>",
    "15": "<p>A theme: Abdon died and was buried in Pirathon in the land of Ephraim, &ldquo;in the hill country of the Amalekites.&rdquo; The Amalekites — the persistent enemy from the wilderness wanderings — still have a named presence in the land at this point. Their enduring territorial identification is a reminder that partial conquest leaves enemies in place; only the final conquest of Christ will eliminate every hostile presence from the inheritance (Rev 21:4: &ldquo;neither shall there be mourning, nor crying, nor pain anymore&rdquo;).</p>"
  },
  "13": {
    "1": "<p>A theme: &ldquo;And the people of Israel again did what was evil in the sight of the LORD, so the LORD gave them into the hand of the Philistines for forty years.&rdquo; The Deuteronomic cycle restarts. Forty years — a generation — is the exact span of Israel&rsquo;s wilderness judgment (Num 14:33-34) and anticipates the forty-year generation before the temple&rsquo;s destruction in AD 70 (Luke 21:32). The recurring cycle of apostasy and judgment is the formal demonstration that no human deliverer breaks the pattern. The forty-year Philistine oppression frames the entire Samson narrative and demands a deliverer of a wholly different order — one who can permanently end the cycle.</p>",
    "2": "<p>A shadow: a certain man named Manoah of Zorah has a wife who is barren and has borne no children. The barren wife who will miraculously bear a deliverer is a cumulative OT type: Sarah (Isaac), Rebekah (Jacob), Rachel (Joseph), Hannah (Samuel), and Elizabeth (John the Baptist) all follow this pattern, each leading typologically toward the climactic miraculous birth — the virgin birth of Christ (Luke 1:7, 34-35). Each impossible birth announces that the coming child is not the product of natural generation alone but a special act of divine provision.</p>",
    "3": "<p>A type: the Angel of the LORD appears to the woman and announces her coming pregnancy. The <em>malʾak YHWH</em> who appears with an annunciation follows the pattern of Gen 18 (the three visitors to Sarah), Gen 16 (Hagar at Beer-lahai-roi), Gen 21:17 (the angel calling to Hagar). This Angel, who speaks as YHWH in the first person and is identified with YHWH himself (v22), is the pre-incarnate Son — the same one who will himself be born of a woman (Gal 4:4), arriving first as the announcing messenger and ultimately as the announced child.</p>",
    "4": "<p>A shadow: the Angel instructs the woman to abstain from wine and strong drink and from anything unclean — the Nazirite purity requirements applied to the mother during pregnancy. The child&rsquo;s holiness is to characterize the entire period of his formation, from before birth. This points to Christ, who was holy not from a postnatal vow but from conception (Luke 1:35: &ldquo;the Holy Spirit will come upon you, and the power of the Most High will overshadow you; therefore the child to be born will be called holy — the Son of God&rdquo;).</p>",
    "5": "<p>A type: &ldquo;For behold, you shall conceive and bear a son. No razor shall come upon his head, for the child shall be a Nazirite to God from the womb, and he shall begin to save Israel from the hand of the Philistines.&rdquo; The phrase &ldquo;he shall begin to save&rdquo; is crucial: Samson is explicitly a partial deliverer, one who begins what another must complete. John the Baptist stands in this same typological position — the Nazirite from the womb (Luke 1:15) who begins the preparation but points to the one coming after him who will complete the salvation (John 1:29-30).</p>",
    "6": "<p>A theme: the woman reports the angelic visit to her husband. She describes the visitor as &ldquo;a man of God&rdquo; whose &ldquo;appearance was like the appearance of the angel of God, very awesome.&rdquo; She perceived both the human form and the terrifying divine quality simultaneously. The incarnation makes exactly this combination permanent: in Christ, the appearance of a man and the reality of divine glory coexist, the latter breaking through at the transfiguration (Matt 17:2) and the resurrection (Rev 1:13-16).</p>",
    "7": "<p>A theme: the woman repeats the Nazirite instructions to her husband — no wine, no strong drink, nothing unclean. The transmission of the divine instruction through the woman to the household mirrors the way covenant knowledge is passed through the community: what the Lord reveals, the community rehearses, teaches, and embodies. The household shaped by the divine word becomes the environment in which the Spirit-designated deliverer is formed.</p>",
    "8": "<p>A theme: Manoah prays: &ldquo;O Lord, please let the man of God whom you sent come again to us and teach us what we are to do with the child who will be born.&rdquo; The prayer for renewed divine instruction in how to raise the appointed deliverer models the posture of those who receive God&rsquo;s gifts: not presumptuous confidence in their own instincts but prayerful dependence on divine guidance. Those who raise children in the covenant context seek wisdom from the same God who gave the child (Jas 1:5).</p>",
    "9": "<p>A theme: &ldquo;God listened to the voice of Manoah, and the angel of God came again to the woman.&rdquo; The answered prayer — the return of the divine messenger — confirms that YHWH responds to earnest seeking. Christ taught the same principle with absolute confidence: &ldquo;Ask, and it will be given to you; seek, and you will find; knock, and it will be opened to you&rdquo; (Matt 7:7). The intercessory pattern of Manoah points to the Christ who &ldquo;always lives to make intercession&rdquo; (Heb 7:25).</p>",
    "10": "<p>A theme: the woman runs quickly to tell her husband, &ldquo;Behold, the man who came to me the other day has appeared to me.&rdquo; The urgent summons of the husband to encounter the divine visitor parallels the women at the empty tomb who &ldquo;ran to tell his disciples&rdquo; the resurrection news (Matt 28:8). In both cases, women are the first to receive and transmit the announcement of the divine presence breaking into the world.</p>",
    "11": "<p>A theme: Manoah follows his wife and asks the Angel directly, &ldquo;Are you the man who spoke to this woman?&rdquo; The encounter moves from indirect report to direct encounter. The NT pattern is the same: the gospel is first received through witnesses, but it leads to personal encounter. Thomas goes from hearing reports about the risen Christ to addressing him directly: &ldquo;My Lord and my God!&rdquo; (John 20:28).</p>",
    "12": "<p>A theme: Manoah asks, &ldquo;Now when your words come true, what is to be the rule for the child, and what is to be done for him?&rdquo; The question presupposes that the Angel&rsquo;s word will certainly come true — the conditional &ldquo;when,&rdquo; not &ldquo;if.&rdquo; This confidence in the reliability of the divine announcement is the model of covenant faith: taking God&rsquo;s promises as settled realities that determine the present pattern of life. Abraham acted &ldquo;as good as dead&rdquo; toward God&rsquo;s promise but &ldquo;did not weaken in faith&rdquo; (Rom 4:19-20).</p>",
    "13": "<p>A theme: the Angel restates the Nazirite requirements. The repetition of the divine instructions is not redundancy but emphasis: the requirements for the life of the consecrated one are non-negotiable and permanent. Samson&rsquo;s later violations of every aspect of his Nazirite vow make this repetition poignant in retrospect. The law that was rehearsed twice was broken repeatedly — until Christ, who kept every divine requirement perfectly, fulfilling all that the Nazirite consecration pointed toward.</p>",
    "14": "<p>A theme: the woman is to do as the Angel said — abstaining from anything the vine produces, wine, strong drink, or unclean things. The Nazirite abstinences represented a posture of total consecration, set apart from ordinary life for YHWH&rsquo;s purpose. Christ&rsquo;s own consecration was not ritual abstinence but moral and relational totality: wholly given to the Father&rsquo;s will, set apart from sin while fully engaging the world (John 17:19: &ldquo;for their sake I consecrate myself, that they also may be sanctified in truth&rdquo;).</p>",
    "15": "<p>A theme: Manoah asks the Angel to stay while he prepares a young goat. The hospitality offer — the same gesture Abraham extended to the three visitors in Gen 18 — is the human response to divine presence: offer what you can, what you have. The instinct to provide, to honor, to hold the divine visitor longer, mirrors the disciples on the Emmaus road: &ldquo;Stay with us, for it is toward evening&rdquo; (Luke 24:29). The desire to extend the encounter with the divine presence is itself an expression of faith and love.</p>",
    "16": "<p>A revelation of God: the Angel refuses the food, saying &ldquo;if you detain me, I will not eat of your food; but if you want to make a burnt offering, offer it to the LORD.&rdquo; The Angel will not accept worship directed to himself but redirects it to YHWH — yet the narrator adds that Manoah did not know he was the Angel of the LORD. The self-effacing redirection of glory to the Father mirrors Christ&rsquo;s own characteristic humility (John 7:18; 8:50: &ldquo;I do not seek my own glory&rdquo;), while the Angel&rsquo;s true identity remains veiled until the moment of self-disclosure.</p>",
    "17": "<p>A theme: Manoah asks the Angel his name &ldquo;so that, when your words come true, we may honor you.&rdquo; The desire to know the name of the divine visitor — in order to honor him properly when his word is fulfilled — points to the NT pattern of invoking the name of Jesus. To confess his name is to honor the one whose words have come true; the risen Christ is worshiped by name because his prediction — &ldquo;I will rise on the third day&rdquo; — was fulfilled exactly (Matt 28:9; Phil 2:9-11).</p>",
    "18": "<p>A type: &ldquo;Why do you ask my name, seeing it is <em>pelîʾî</em>?&rdquo; — wonderful, incomprehensible, beyond telling. The Angel&rsquo;s name is <em>pelîʾ</em>, the same root as the first of the messianic titles in Isa 9:6: &ldquo;his name shall be called Wonderful (<em>peleʾ</em>) Counselor, Mighty God, Everlasting Father, Prince of Peace.&rdquo; The Angel at the annunciation of Samson&rsquo;s birth declares a name that is beyond human grasp — the name that will be fully disclosed in the incarnate Son. The incomprehensible name of the pre-incarnate Word becomes in Christ the name that every tongue confesses (Phil 2:11).</p>",
    "19": "<p>A type: Manoah takes the young goat and the grain offering and offers them on the rock to YHWH, &ldquo;and the Angel did wonders (<em>maplîʾ</em>, from the same root as <em>pelîʾî</em>)&rdquo; — the Angel performs wonders of the same quality as his name. The fire ascending from the rock as the offering burns points to the altar of divine acceptance: the sacrifice consumed by YHWH&rsquo;s own fire. The rock as altar anticipates Christ as the rock (1 Cor 10:4) on whom the sacrifice is made and from whom the fire of the Spirit goes forth at Pentecost.</p>",
    "20": "<p>A type: &ldquo;When the flame went up toward heaven from the altar, the angel of the LORD went up in the flame of the altar. And Manoah and his wife looked on and fell on their faces to the ground.&rdquo; The ascent of the Angel in the flame of the sacrifice is the most explicit pre-incarnate ascension in the OT. The same movement — presence descending to announce, then ascending after the work is done — governs the Christ narrative: the Word descends into human flesh, accomplishes the sacrifice, and ascends to the Father (John 13:3; Eph 4:8-10). Manoah and his wife fall on their faces — the posture of all who encounter the ascended Christ (Rev 1:17).</p>",
    "21": "<p>A theme: &ldquo;The Angel of the LORD appeared no more to Manoah and to his wife.&rdquo; The work of announcement is complete; the messenger does not linger. The once-for-all nature of the angelic visitation at this annunciation parallels the once-for-all nature of the incarnation (Heb 9:26: &ldquo;he has appeared once for all at the end of the ages to put away sin by the sacrifice of himself&rdquo;). After the sacrifice-annunciation, the divine presence withdraws in its visible form, but its effects remain.</p>",
    "22": "<p>A theme: Manoah says &ldquo;We shall surely die, for we have seen God.&rdquo; The terror of unmediated divine encounter — grounded in the &ldquo;no one can see God and live&rdquo; principle (Exod 33:20) — drives the question of how sinners can survive divine presence. The incarnation answers this terror: God takes human form so that humans can behold his glory &ldquo;full of grace and truth&rdquo; (John 1:14) without being consumed. The fear Manoah expresses is the fear that the gospel addresses.</p>",
    "23": "<p>A revelation of God: the wife&rsquo;s theological reasoning is profound: &ldquo;If the LORD had meant to kill us, he would not have accepted a burnt offering and grain offering at our hands, or shown us all these things, or now announced to us such things as these.&rdquo; She argues from divine consistency: the God who accepts the sacrifice does not then destroy the worshiper. The same argument underlies Paul&rsquo;s reasoning in Romans 8:32: &ldquo;He who did not spare his own Son but gave him up for us all, how will he not also with him graciously give us all things?&rdquo; The acceptance of the offering is the guarantee of the worshiper&rsquo;s safety.</p>",
    "24": "<p>A theme: &ldquo;The woman bore a son and called his name Samson. And the young man grew, and the LORD blessed him.&rdquo; The promised child arrives as announced; the blessing of YHWH accompanies his growth. The pattern of the promised child born, growing, and blessed by God is the template for the gospel narrative: &ldquo;And Jesus increased in wisdom and in stature and in favor with God and man&rdquo; (Luke 2:52). Every miraculous birth in the OT prepares the community to recognize the pattern when it reaches its eschatological fulfillment.</p>",
    "25": "<p>A type: &ldquo;And the Spirit of the LORD began to stir him in Mahaneh-dan, between Zorah and Eshtaol.&rdquo; The Spirit&rsquo;s stirring of Samson before his public ministry begins mirrors the Spirit&rsquo;s rest on Jesus at his baptism (Matt 3:16) before his public ministry commences. The Hebrew root <em>pāʿam</em> (stir, impel, thrust) suggests the dynamic, driving quality of the Spirit&rsquo;s activity — not a gentle disposition but an urgent commission. Christ&rsquo;s own anointing by the Spirit &ldquo;without measure&rdquo; (John 3:34) is the fulfillment of every partial Spirit-stirring in the deliverer narratives of Judges.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'judges')
    merge_comm(existing, JUDGES)
    save_comm('mkt-christ', 'judges', existing)

    import json as _j
    il = _j.load(open(ROOT / 'data' / 'interlinear' / 'judges.json'))
    all_ok = True
    for ch in [11, 12, 13]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(existing.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(existing.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present ✓')
    chs = sorted(existing.keys(), key=int)
    print(f'Judges mkt-christ chapters now: {chs} ({len(chs)}/21)')

if __name__ == '__main__':
    main()
